mapper.select:
SELECT FROM erp_leave_requests lr LEFT JOIN erp_employees e ON lr.employee_id = e.id LEFT JOIN users u ON e.user_id = u.id LEFT JOIN erp_employees ap ON lr.approver_id = ap.id LEFT JOIN users apu ON ap.user_id = apu.id WHERE lr.employee_id = #{employeeId}::uuid
AND lr.status = #{status}
ORDER BY lr.created_at DESC

SELECT FROM erp_leave_requests lr LEFT JOIN erp_employees e ON lr.employee_id = e.id LEFT JOIN users u ON e.user_id = u.id LEFT JOIN erp_employees ap ON lr.approver_id = ap.id LEFT JOIN users apu ON ap.user_id = apu.id WHERE e.department_id IN ( SELECT id FROM erp_departments WHERE manager_id = #{managerId}::uuid )
AND lr.status = #{status}
ORDER BY lr.created_at DESC
